mapper.update:

update fnd_dept_snapshot
   set
       update_by     = #{updateBy,jdbcType=BIGINT},
       update_time   = #{updateTime,jdbcType=TIMESTAMP},
       attendance_id = #{attendanceId,jdbcType=BIGINT}
 where id = #{id,jdbcType=BIGINT}

mapper.select:
select
,
from fnd_dept_snapshot fds left join ac_dept_attendance ada on fds.dept_id = ada.dept_id and fds.date between ada.take_effect_date and ISNULL(ada.invalid_date, fds.date) AND ada.enabled_flag = 1 where fds.date = #{date, jdbcType=DATE}

select from fnd_dept_snapshot fds where 1 =1
and fds.date = '${criteria.dateStr}'
and fds.dept_id = #{deptId, jdbcType = BIGINT}
